class Solution {
public:
    int findIntegers(int n) {
        int dp[2][2] = {{1, 1}, {1, 0}};
        int res = 0;
        for (int i = 30; i >= 0; --i) {
            int bit = (n >> i) & 1;
            res += dp[bit][0] + dp[bit][1];
            dp[0][0] = dp[bit][1];
            dp[0][1] = 0;
            dp[1][0] = dp[1][bit];
            dp[1][1] = dp[bit][1];
        }
        return res;
    }
};
```
